SELECT population
FROM population_trends
WHERE city_id = 1 AND year = 2020;

SELECT project_name 
FROM urban_developments 
WHERE city_id = 1;

SELECT city_name, latitude, longitude, country_code
FROM cities
WHERE population > 1000000;

SELECT image_url 
FROM city_images 
WHERE city_id = (
  SELECT city_id 
  FROM cities 
  WHERE elevation = (
    SELECT MAX(elevation) 
    FROM cities
  )
);

SELECT c.city_name, c.population, c.country_code
FROM cities c
JOIN city_statistics s ON c.city_id = s.city_id
WHERE s.population_density > (
  SELECT AVG(population_density) FROM city_statistics
);
